const headers = $json.headers || {};
const role = String(headers["x-user-role"] || "").trim().toLowerCase();
const id = String(headers["x-user-id"] || role || "").trim();
const name = String(headers["x-user-name"] || role || "").trim();

if (!role) {
  return { json: { statusCode: 401, error: "expired", code: "session_missing" } };
}

return {
  json: {
    action: $json.action,
    session: { id, name, role },
    params: $json.params || {},
    body: $json.body || {},
  },
};

const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  IDEA_TITLE_FIELD: $env.AIRTABLE_IDEA_TITLE_FIELD || "title",
  IDEA_DESCRIPTION_FIELD: $env.AIRTABLE_IDEA_DESCRIPTION_FIELD || "description",
  IDEA_STATUS_FIELD: $env.AIRTABLE_IDEA_STATUS_FIELD || "status",
  IDEA_PROPOSED_BY_FIELD: $env.AIRTABLE_IDEA_PROPOSED_BY_FIELD || "proposed_by",
  IDEA_LIKES_FIELD: $env.AIRTABLE_IDEA_LIKES_FIELD || "likes",
  IDEA_DISLIKES_FIELD: $env.AIRTABLE_IDEA_DISLIKES_FIELD || "dislikes",
};

const request = this.helpers.httpRequest.bind(this.helpers);
const apiKey = String(CONFIG.AIRTABLE_PAT || "").trim();
const baseId = String(CONFIG.AIRTABLE_BASE_ID || "").trim();

if (!apiKey || !baseId) {
  return { json: { statusCode: 500, error: "Airtable config missing in n8n environment", code: "airtable_config_missing" } };
}

const airtable = "https://api.airtable.com/v0/" + baseId;
const headers = { Authorization: "Bearer " + apiKey };
const action = String($json.action || "");
const session = $json.session;
const body = $json.body || {};
const params = $json.params || {};
const titleField = CONFIG.IDEA_TITLE_FIELD;
const descriptionField = CONFIG.IDEA_DESCRIPTION_FIELD;
const statusField = CONFIG.IDEA_STATUS_FIELD;
const proposedByField = CONFIG.IDEA_PROPOSED_BY_FIELD;
const likesField = CONFIG.IDEA_LIKES_FIELD;
const dislikesField = CONFIG.IDEA_DISLIKES_FIELD;
const IDEA_FIELDS = [titleField, descriptionField, statusField, proposedByField, likesField, dislikesField];

const escapeFormulaString = (value) => String(value || "").replace(/'/g, "\\'");
const fieldsQuery = (fields) => fields.filter(Boolean).map((field) => "fields%5B%5D=" + encodeURIComponent(field)).join("&");
const linkedIds = (value) => Array.isArray(value) ? value.map(String) : value ? [String(value)] : [];
const first = (value) => Array.isArray(value) ? value[0] : value;
const roleLabel = (role) => ({
  samuel: "Samuel",
  mathilde: "Mathilde",
  amis_samuel: "Amis de Samuel",
  amis_mathilde: "Amis de Mathilde",
}[role] || role || "");

async function findUserRecord(currentSession) {
  const userId = String(currentSession?.id || "").trim();
  const role = String(currentSession?.role || "").trim().toLowerCase();
  if (userId) {
    try {
      return await request({ method: "GET", url: airtable + "/Users/" + encodeURIComponent(userId), headers, json: true });
    } catch {}
  }

  try {
    const roleFormula = "LOWER({role}) = '" + escapeFormulaString(role) + "'";
    const data = await request({ method: "GET", url: airtable + "/Users?maxRecords=1&filterByFormula=" + encodeURIComponent(roleFormula), headers, json: true });
    if (data.records?.[0]) return data.records[0];
  } catch {}

  try {
    const idFormula = "{id} = '" + escapeFormulaString(userId) + "'";
    const data = await request({ method: "GET", url: airtable + "/Users?maxRecords=1&filterByFormula=" + encodeURIComponent(idFormula), headers, json: true });
    return data.records?.[0] || null;
  } catch {}

  return null;
}

async function findIdeaRecord(id) {
  const cleanId = String(id || "").trim();
  if (!cleanId) return null;
  try {
    return await request({ method: "GET", url: airtable + "/Ideas/" + encodeURIComponent(cleanId), headers, json: true });
  } catch {}

  try {
    const recordIdFormula = "RECORD_ID() = '" + escapeFormulaString(cleanId) + "'";
    const data = await request({ method: "GET", url: airtable + "/Ideas?maxRecords=1&filterByFormula=" + encodeURIComponent(recordIdFormula) + "&" + fieldsQuery(IDEA_FIELDS), headers, json: true });
    if (data.records?.[0]) return data.records[0];
  } catch {}

  try {
    const customIdFormula = "{id} = '" + escapeFormulaString(cleanId) + "'";
    const data = await request({ method: "GET", url: airtable + "/Ideas?maxRecords=1&filterByFormula=" + encodeURIComponent(customIdFormula) + "&" + fieldsQuery(IDEA_FIELDS), headers, json: true });
    return data.records?.[0] || null;
  } catch {}

  return null;
}

async function listIdeaRecords() {
  const records = [];
  let offset = "";
  do {
    const url = airtable + "/Ideas?" + fieldsQuery(IDEA_FIELDS) + "&pageSize=100" + (offset ? "&offset=" + encodeURIComponent(offset) : "");
    const data = await request({ method: "GET", url, headers, json: true });
    records.push(...(data.records || []));
    offset = data.offset || "";
  } while (offset);
  return records;
}

function ideaFromRecord(record, userRecord) {
  const f = record.fields || {};
  const userId = userRecord?.id || "";
  const userName = String(userRecord?.fields?.name || session.name || roleLabel(session.role));
  const likes = linkedIds(f[likesField]);
  const dislikes = linkedIds(f[dislikesField]);
  return {
    id: record.id,
    title: String(f[titleField] || ""),
    description: String(f[descriptionField] || ""),
    proposed_by_id: first(f[proposedByField]) || "",
    proposed_by_name: String(first(f.proposed_by_name) || userName),
    status: String(f[statusField] || "voting"),
    likes,
    dislikes,
    my_vote: likes.includes(userId) ? "like" : dislikes.includes(userId) ? "dislike" : null,
  };
}

const user = (await findUserRecord(session)) || {
  id: String(session.id || session.role || ""),
  fields: { name: session.name, role: session.role },
  fallback: true,
};

if (action === "list") {
  const ideas = (await listIdeaRecords()).map((record) => ideaFromRecord(record, user));
  return { json: { ideas } };
}

if (action === "create") {
  const title = String(body.title || "").trim();
  const description = String(body.description || "").trim();
  if (!title) {
    return { json: { statusCode: 400, error: "title is required", code: "idea_invalid" } };
  }

  let created;
  const baseFields = { [titleField]: title, [descriptionField]: description, [statusField]: "voting", [likesField]: [], [dislikesField]: [] };
  const createFields = user.fallback ? baseFields : { ...baseFields, [proposedByField]: [user.id] };
  try {
    created = await request({
      method: "POST",
      url: airtable + "/Ideas",
      headers,
      body: { fields: createFields },
      json: true,
    });
  } catch (error) {
    const message = String(error?.message || error || "");
    if (!user.fallback && message.includes(proposedByField)) {
      try {
        created = await request({ method: "POST", url: airtable + "/Ideas", headers, body: { fields: baseFields }, json: true });
      } catch (retryError) {
        return { json: { statusCode: 500, error: "Airtable idea create failed: " + (retryError?.message || String(retryError)), code: "airtable_idea_create_failed" } };
      }
    } else {
      return { json: { statusCode: 500, error: "Airtable idea create failed: " + (error?.message || String(error)), code: "airtable_idea_create_failed" } };
    }
  }
  return { json: { idea: ideaFromRecord(created, user) } };
}

if (action === "vote") {
  const kind = String(body.kind || "").trim();
  if (!["like", "dislike", "clear"].includes(kind)) {
    return { json: { statusCode: 400, error: "kind must be like, dislike or clear", code: "idea_vote_invalid" } };
  }

  const idea = await findIdeaRecord(params.id);
  if (!idea) {
    return { json: { statusCode: 404, error: "Idea not found", code: "idea_missing" } };
  }

  const f = idea.fields || {};
  const likes = linkedIds(f[likesField]).filter((id) => id !== user.id);
  const dislikes = linkedIds(f[dislikesField]).filter((id) => id !== user.id);
  if (kind === "like") likes.push(user.id);
  if (kind === "dislike") dislikes.push(user.id);

  let updated;
  try {
    updated = await request({
      method: "PATCH",
      url: airtable + "/Ideas/" + idea.id,
      headers,
      body: { fields: { [likesField]: likes, [dislikesField]: dislikes } },
      json: true,
    });
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable idea vote failed: " + (error?.message || String(error)), code: "airtable_idea_vote_failed" } };
  }
  return { json: { idea: ideaFromRecord(updated, user) } };
}

if (action === "status") {
  if (!["samuel", "mathilde"].includes(session.role)) {
    return { json: { statusCode: 403, error: "forbidden", code: "idea_status_forbidden" } };
  }

  const status = String(body.status || "").trim();
  if (!["voting", "selected", "scheduled", "done"].includes(status)) {
    return { json: { statusCode: 400, error: "invalid status", code: "idea_status_invalid" } };
  }

  const idea = await findIdeaRecord(params.id);
  if (!idea) {
    return { json: { statusCode: 404, error: "Idea not found", code: "idea_missing" } };
  }

  let updated;
  try {
    updated = await request({ method: "PATCH", url: airtable + "/Ideas/" + idea.id, headers, body: { fields: { [statusField]: status } }, json: true });
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable idea status failed: " + (error?.message || String(error)), code: "airtable_idea_status_failed" } };
  }
  return { json: { idea: ideaFromRecord(updated, user) } };
}

return { json: { statusCode: 404, error: "unknown ideas action", code: "ideas_action_missing" } };
